import numpy as np
from collections import defaultdict
import heapq

class QuantumNetwork:
    def __init__(self):
        self.nodes = {}
        self.links = {}

    def add_node(self, name, node_type='end_node'):
        self.nodes[name] = {'type': node_type}

    def add_link(self, node1, node2, distance_km):
        loss_db = 0.2 * distance_km
        p_success = 10 ** (-loss_db / 10)
        key = tuple(sorted([node1, node2]))
        self.links[key] = {'distance': distance_km, 'p_success': p_success}

    def find_best_path(self, source, destination):
        adj = defaultdict(list)
        for (n1, n2), link in self.links.items():
            w = -np.log(link['p_success'])
            adj[n1].append((n2, w))
            adj[n2].append((n1, w))

        dist = {n: float('inf') for n in self.nodes}
        prev = {n: None for n in self.nodes}
        dist[source] = 0
        pq = [(0, source)]

        while pq:
            d, u = heapq.heappop(pq)
            if d > dist[u]: continue
            for v, w in adj[u]:
                if dist[u] + w < dist[v]:
                    dist[v] = dist[u] + w
                    prev[v] = u
                    heapq.heappush(pq, (dist[v], v))

        path = []
        node = destination
        while node:
            path.append(node)
            node = prev[node]
        path.reverse()

        return path, np.exp(-dist[destination])

net = QuantumNetwork()
net.add_node('Alice')
net.add_node('R1', 'repeater')
net.add_node('Bob')
net.add_link('Alice', 'R1', 50)
net.add_link('R1', 'Bob', 50)
path, prob = net.find_best_path('Alice', 'Bob')
print(f'Path: {path}, Probability: {prob:.6f}')

import numpy as np

def classical_precision(num_sensors, noise):
    return noise / np.sqrt(num_sensors)

def quantum_precision(num_sensors, noise):
    return noise / num_sensors

print('Sensor Network Precision Comparison')
print('=' * 50)
for N in [10, 100, 1000]:
    c = classical_precision(N, 1.0)
    q = quantum_precision(N, 1.0)
    improvement = c / q
    print(f'N={N:4d}: Classical={c:.6f}, Quantum={q:.6f}, Improvement={improvement:.1f}x')

